import React, { useEffect, useState, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { fetchProducts } from '../store/slices/productslice';
import ProductCard from '../components/product/productcart';
import LoadingSpinner from '../components/common/lodingspinner';
import { MOCK_PRODUCTS } from '../utils/mockproducts';
import { ChevronDown, SlidersHorizontal, X } from 'lucide-react';

const SIDEBAR_CATEGORIES = {
    'LIVING ROOM': {
        'SOFAS': ['Fabric Sofas', 'Wooden Sofas', 'L-Shaped Sofas', 'Sofa Cum Beds', 'Recliners'],
        'SEATING': ['Lounge Chairs', 'Accent Chairs', 'Wing Chairs', 'Benches', 'Pouffes'],
        'TABLES': ['Coffee Tables', 'Side Tables', 'Console Tables', 'End Tables'],
        'STORAGE': ['TV Units', 'Bookshelves', 'Display Units', 'Shoe Racks']
    },
    'BEDROOM': {
        'BEDS': ['Solid Wood Beds', 'Upholstered Beds', 'Beds with Storage', 'King Size Beds', 'Queen Size Beds'],
        'STORAGE': ['Wardrobes', 'Chest of Drawers', 'Bedside Tables', 'Dressers'],
        'MATTRESSES': ['Memory Foam', 'Orthopedic', 'Dual Comfort', 'Coir Mattresses']
    },
    'DINING': {
        'DINING SETS': ['4 Seater Dining Sets', '6 Seater Dining Sets', '8 Seater Dining Sets', 'Extendable Dining'],
        'DINING STORAGE': ['Crockery Units', 'Kitchen Cabinets', 'Sideboards'],
        'DINING DECOR': ['Table Linens', 'Coasters', 'Dining Serveware']
    },
    'STUDY': {
        'STUDY TABLES': ['Solid Wood Tables', 'Computer Tables', 'Foldable Tables'],
        'OFFICE CHAIRS': ['Ergonomic Chairs', 'Executive Chairs', 'Study Chairs'],
        'OFFICE STORAGE': ['File Cabinets', 'Office Bookcases', 'Wall Shelves']
    }
};

const AllProductsPage = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();

    const [selectedCategory, setSelectedCategory] = useState(
        searchParams.get('category') || 'all'
    );
    const [activeAccordion, setActiveAccordion] = useState(null);
    const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest');
    const [page, setPage] = useState(parseInt(searchParams.get('page')) || 1);

    // Mobile Drawer State
    const [isMobileFiltersOpen, setIsMobileFiltersOpen] = useState(false);

    const { items: apiItems, loading, error } = useSelector(
        (state) => state.products
    );

    const items = useMemo(() => {
        return (apiItems && apiItems.length > 0) ? apiItems : MOCK_PRODUCTS;
    }, [apiItems]);

    const useMockData = useMemo(() => {
        return (!apiItems || apiItems.length === 0);
    }, [apiItems]);

    const filteredProducts = useMemo(() => {
        if (selectedCategory === 'all') return items;
        return items.filter(product => {
            const mainMatch = product.category?.toUpperCase() === selectedCategory.toUpperCase();
            const subMatch = product.subCategory?.toUpperCase() === selectedCategory.toUpperCase();
            return mainMatch || subMatch;
        });
    }, [items, selectedCategory]);

    const sortedProducts = useMemo(() => {
        return [...filteredProducts].sort((a, b) => {
            const priceA = a.variants?.[0]?.price || a.finalPrice || 0;
            const priceB = b.variants?.[0]?.price || b.finalPrice || 0;
            switch (sortBy) {
                case 'price_low': return priceA - priceB;
                case 'price_high': return priceB - priceA;
                case 'popular': return (b.rating || 0) - (a.rating || 0);
                case 'rating': return (b.rating || 0) - (a.rating || 0);
                case 'newest':
                default: return 0;
            }
        });
    }, [filteredProducts, sortBy]);

    const startIdx = (page - 1) * 20;
    const paginatedProducts = sortedProducts.slice(startIdx, startIdx + 20);
    const calculatedTotalPages = Math.ceil(sortedProducts.length / 20);

    useEffect(() => {
        const params = { page, limit: 20 };
        if (selectedCategory !== 'all') params.category = selectedCategory;
        if (sortBy !== 'newest') params.sort = sortBy;

        if (!useMockData) dispatch(fetchProducts(params));

        const newSearchParams = new URLSearchParams();
        if (selectedCategory !== 'all') newSearchParams.set('category', selectedCategory);
        if (sortBy !== 'newest') newSearchParams.set('sort', sortBy);
        if (page !== 1) newSearchParams.set('page', page);
        setSearchParams(newSearchParams);
    }, [dispatch, selectedCategory, sortBy, page, setSearchParams, useMockData]);

    // Prevent background scrolling when mobile drawer is open
    useEffect(() => {
        if (isMobileFiltersOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'unset';
        }
        return () => { document.body.style.overflow = 'unset'; };
    }, [isMobileFiltersOpen]);

    const handleMainCategoryClick = (mainCat) => {
        setActiveAccordion(activeAccordion === mainCat ? null : mainCat);
        setSelectedCategory(mainCat);
        setPage(1);
    };

    const handleSubCategoryClick = (subCat) => {
        setSelectedCategory(subCat);
        setPage(1);
        // Safely close drawer only on touch devices (width < 768px matches Tailwind's 'md')
        if (window.innerWidth < 768) setIsMobileFiltersOpen(false);
    };

    const handleSortChange = (e) => {
        setSortBy(e.target.value);
        setPage(1);
    };

    const getDisplayCategory = () => {
        if (selectedCategory === 'all') return 'All Products';
        return selectedCategory.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ');
    };

    if (error && !useMockData) {
        return (
            <div className="bg-[#FAFAFA] min-h-screen py-12">
                <div className="container mx-auto px-4 text-center">
                    <h1 className="text-3xl font-bold text-red-600 mb-4">Error Loading Products</h1>
                    <p className="text-slate-600 mb-6">{error}</p>
                    <button onClick={() => window.location.reload()} className="bg-orange-600 text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-700 transition-colors outline-none focus:outline-none">
                        Try Again
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-white min-h-screen font-sans relative">

            {/* --- HEADER AREA --- */}
            <div className="bg-white border-b border-slate-200 py-6 md:py-12">
                <div className="container mx-auto px-4 md:px-8 xl:px-12 max-w-[1600px]">
                    <div className="mb-4 md:mb-6">
                        <button
                            onClick={() => navigate('/')}
                            className="text-slate-400 text-sm hover:text-slate-900 transition-colors flex items-center gap-2 outline-none focus:outline-none focus-visible:outline-none select-none py-2"
                            style={{ WebkitTapHighlightColor: 'transparent' }}
                        >
                            <span className="transition-transform">←</span>
                            Back to Home
                        </button>
                    </div>
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-5">
                        <div>
                            <h1 className="text-3xl md:text-4xl lg:text-5xl font-bold text-slate-900 mb-2 md:mb-3 tracking-tight">
                                {getDisplayCategory()}
                            </h1>
                            <p className="text-slate-500 text-sm md:text-base font-medium select-none">
                                Showing {paginatedProducts.length > 0 ? startIdx + 1 : 0} - {startIdx + paginatedProducts.length} of {sortedProducts.length} products
                            </p>
                        </div>

                        {/* Mobile Filter Toggle Button (Hidden on Tablets & Desktop) */}
                        <button
                            onClick={() => setIsMobileFiltersOpen(true)}
                            className="md:hidden flex items-center justify-center gap-2 w-full bg-slate-50 border border-slate-200 text-slate-900 py-3.5 rounded-lg font-semibold hover:bg-slate-100 transition-colors outline-none focus:outline-none focus-visible:outline-none select-none"
                            style={{ WebkitTapHighlightColor: 'transparent' }}
                        >
                            <SlidersHorizontal size={18} />
                            Filter & Sort
                        </button>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 md:px-8 xl:px-12 py-8 md:py-12 max-w-[1600px]">
                <div className="grid grid-cols-12 gap-6 lg:gap-10 xl:gap-14">

                    {/* --- MOBILE OVERLAY (Dark background when drawer opens) --- */}
                    {isMobileFiltersOpen && (
                        <div
                            className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-40 md:hidden transition-opacity duration-300"
                            onClick={() => setIsMobileFiltersOpen(false)}
                        />
                    )}

                    {/* --- LEFT SIDEBAR (Mobile Drawer OR Desktop Sidebar) --- */}
                    <div className={`
                        fixed top-0 left-0 z-50 w-[85%] max-w-[360px] h-[100dvh] bg-white shadow-2xl transform transition-transform duration-300 ease-in-out flex flex-col
                        md:static md:w-auto md:max-w-none md:h-auto md:bg-transparent md:shadow-none md:transform-none md:translate-x-0 md:block
                        col-span-12 md:col-span-4 lg:col-span-3 xl:col-span-3
                        ${isMobileFiltersOpen ? 'translate-x-0' : '-translate-x-full'}
                    `}>

                        {/* Drawer Header (Only visible on Mobile) */}
                        <div className="flex-shrink-0 flex items-center justify-between p-6 border-b border-slate-100 md:hidden bg-white">
                            <h2 className="text-xl font-bold text-slate-900 tracking-tight">Filters</h2>
                            <button
                                onClick={() => setIsMobileFiltersOpen(false)}
                                className="p-2 -mr-2 text-slate-400 hover:text-slate-900 transition-colors outline-none focus:outline-none focus-visible:outline-none rounded-full"
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                            >
                                <X size={22} />
                            </button>
                        </div>

                        {/* Sidebar Scrollable Content */}
                        <div className="flex-1 overflow-y-auto p-6 md:p-0 md:overflow-visible">
                            <div className="space-y-10 md:sticky md:top-24">

                                {/* Categories Accordions */}
                                <div>
                                    <h3 className="hidden md:block text-sm font-bold text-slate-900 mb-6 tracking-widest uppercase">
                                        Categories
                                    </h3>
                                    <div className="space-y-1">

                                        <button
                                            onClick={() => {
                                                setSelectedCategory('all');
                                                setActiveAccordion(null);
                                                setPage(1);
                                                if (window.innerWidth < 768) setIsMobileFiltersOpen(false);
                                            }}
                                            className="w-full flex items-center justify-between py-3 md:py-2.5 outline-none focus:outline-none focus-visible:outline-none select-none"
                                            style={{ WebkitTapHighlightColor: 'transparent' }}
                                        >
                                            <span className={`text-[15px] transition-colors duration-200 ${selectedCategory === 'all' ? 'text-[#f97316] font-semibold' : 'text-slate-500 hover:text-slate-900'
                                                }`}>
                                                All Products
                                            </span>
                                        </button>

                                        {Object.keys(SIDEBAR_CATEGORIES).map((mainCat) => (
                                            <div key={mainCat} className="flex flex-col border-t border-slate-100/50">
                                                <button
                                                    onClick={() => handleMainCategoryClick(mainCat)}
                                                    className="w-full flex items-center justify-between py-4 outline-none focus:outline-none focus-visible:outline-none select-none group"
                                                    style={{ WebkitTapHighlightColor: 'transparent' }}
                                                >
                                                    <span className={`text-[15px] capitalize transition-colors duration-200 ${activeAccordion === mainCat
                                                            ? 'text-slate-900 font-semibold'
                                                            : 'text-slate-500 font-medium group-hover:text-slate-900'
                                                        }`}>
                                                        {mainCat.toLowerCase()}
                                                    </span>
                                                    <ChevronDown
                                                        size={16}
                                                        className={`transition-transform duration-300 ease-in-out ${activeAccordion === mainCat ? 'rotate-180 text-slate-900' : 'text-slate-300 group-hover:text-slate-500'
                                                            }`}
                                                    />
                                                </button>

                                                <div className={`grid transition-all duration-400 ease-[cubic-bezier(0.4,0,0.2,1)] ${activeAccordion === mainCat ? 'grid-rows-[1fr] opacity-100 mb-4' : 'grid-rows-[0fr] opacity-0'
                                                    }`}>
                                                    <div className="overflow-hidden">
                                                        <div className="space-y-6">
                                                            {Object.entries(SIDEBAR_CATEGORIES[mainCat]).map(([groupName, items]) => (
                                                                <div key={groupName}>
                                                                    <h4 className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest mb-3 pl-2 select-none">{groupName}</h4>
                                                                    <ul className="space-y-1">
                                                                        {items.map(item => (
                                                                            <li key={item}>
                                                                                <button
                                                                                    onClick={() => handleSubCategoryClick(item)}
                                                                                    className="text-sm text-left w-full py-2.5 pl-2 outline-none focus:outline-none focus-visible:outline-none select-none flex items-center"
                                                                                    style={{ WebkitTapHighlightColor: 'transparent' }}
                                                                                >
                                                                                    {/* Interactive Active Dot */}
                                                                                    <span className={`absolute -left-6 w-1.5 h-1.5 rounded-full bg-orange-500 transition-all duration-300 ease-out md:block hidden ${selectedCategory === item ? 'scale-100 opacity-100' : 'scale-50 opacity-0'
                                                                                        }`}></span>

                                                                                    <span className={`transition-colors duration-200 ${selectedCategory === item
                                                                                            ? 'text-[#f97316] font-semibold'
                                                                                            : 'text-slate-500 hover:text-slate-900'
                                                                                        }`}>
                                                                                        {item}
                                                                                    </span>
                                                                                </button>
                                                                            </li>
                                                                        ))}
                                                                    </ul>
                                                                </div>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                {/* Sort By Select Box */}
                                <div className="border-t border-slate-100 pt-8 pb-4 md:pb-0">
                                    <h3 className="text-sm font-bold text-slate-900 mb-4 tracking-widest uppercase select-none">Sort By</h3>
                                    <div className="relative">
                                        <select
                                            value={sortBy}
                                            onChange={handleSortChange}
                                            className="w-full px-4 py-3.5 border border-slate-200 rounded-lg text-slate-700 text-sm font-medium focus:outline-none focus:ring-0 focus:border-slate-400 transition-colors cursor-pointer bg-transparent appearance-none select-none"
                                        >
                                            <option value="newest">Newest Arrivals</option>
                                            <option value="price_low">Price: Low to High</option>
                                            <option value="price_high">Price: High to Low</option>
                                            <option value="popular">Most Popular</option>
                                            <option value="rating">Top Rated</option>
                                        </select>
                                        <ChevronDown size={16} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Mobile Drawer "Show Results" Footer (Fixed at bottom) */}
                        <div className="flex-shrink-0 md:hidden p-4 bg-white border-t border-slate-100 shadow-[0_-4px_15px_-5px_rgba(0,0,0,0.05)]">
                            <button
                                onClick={() => setIsMobileFiltersOpen(false)}
                                className="w-full bg-slate-900 text-white font-bold py-3.5 rounded-lg hover:bg-slate-800 active:scale-[0.98] transition-all outline-none focus:outline-none focus-visible:outline-none select-none"
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                            >
                                Show {filteredProducts.length} Results
                            </button>
                        </div>
                    </div>

                    {/* --- RIGHT CONTENT - Dynamic Grid --- */}
                    {/* The grid-cols adapt based on device size: mobile(1) -> tablet(2) -> laptop(3) -> desktop(4) */}
                    <div className="col-span-12 md:col-span-8 lg:col-span-9 xl:col-span-9">
                        {loading && items.length === 0 ? (
                            <div className="flex justify-center items-center py-32">
                                <LoadingSpinner />
                            </div>
                        ) : paginatedProducts.length === 0 ? (
                            <div className="bg-slate-50 rounded-lg p-10 md:p-16 text-center h-full flex flex-col items-center justify-center border border-slate-100">
                                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mb-6 shadow-sm">
                                    <span className="text-2xl">🔍</span>
                                </div>
                                <h3 className="text-2xl font-bold text-slate-900 mb-3 tracking-tight select-none">No Products Found</h3>
                                <p className="text-slate-500 mb-8 max-w-sm select-none">We couldn't find any items matching your current filters. Try adjusting them or browse our full collection.</p>
                                <button
                                    onClick={() => {
                                        setSelectedCategory('all');
                                        setActiveAccordion(null);
                                    }}
                                    className="bg-slate-900 text-white px-8 py-3.5 rounded-lg font-bold hover:bg-slate-800 transition-colors duration-300 outline-none focus:outline-none focus-visible:outline-none select-none"
                                >
                                    Clear All Filters
                                </button>
                            </div>
                        ) : (
                            <>
                                {/* THE RESPONSIVE GRID KERNEL */}
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 lg:gap-8 mb-12">
                                    {paginatedProducts.map((product) => (
                                        <ProductCard key={product.id || product._id} product={product} />
                                    ))}
                                </div>

                                {/* Responsive Pagination */}
                                {calculatedTotalPages > 1 && (
                                    <div className="flex flex-wrap justify-center items-center gap-1 sm:gap-2 py-8 border-t border-slate-100 mt-8">
                                        <button
                                            onClick={() => setPage(Math.max(1, page - 1))}
                                            disabled={page === 1}
                                            className="px-3 sm:px-4 py-2 border border-slate-200 rounded-lg text-slate-600 text-sm sm:text-base font-medium hover:bg-slate-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors outline-none focus:outline-none focus-visible:outline-none select-none"
                                        >
                                            Prev
                                        </button>

                                        {Array.from({ length: Math.min(calculatedTotalPages, 5) }, (_, i) => {
                                            const pageNum = page > 3 ? page - 2 + i : i + 1;
                                            return pageNum <= calculatedTotalPages ? pageNum : null;
                                        }).map(
                                            (p) => p && (
                                                <button
                                                    key={p}
                                                    onClick={() => setPage(p)}
                                                    className={`w-9 h-9 sm:w-10 sm:h-10 flex items-center justify-center rounded-lg transition-colors font-semibold outline-none focus:outline-none focus-visible:outline-none select-none text-sm sm:text-base ${page === p ? 'bg-slate-900 text-white' : 'text-slate-600 hover:bg-slate-50'
                                                        }`}
                                                >
                                                    {p}
                                                </button>
                                            )
                                        )}

                                        <button
                                            onClick={() => setPage(Math.min(calculatedTotalPages, page + 1))}
                                            disabled={page === calculatedTotalPages}
                                            className="px-3 sm:px-4 py-2 border border-slate-200 rounded-lg text-slate-600 text-sm sm:text-base font-medium hover:bg-slate-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors outline-none focus:outline-none focus-visible:outline-none select-none"
                                        >
                                            Next
                                        </button>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AllProductsPage;
